export default function DocActions({ clientId, docs }: { clientId: string; docs: any[] }) {
            const [selected, setSelected] = useState<string>("");
            const [action, setAction] = useState<"verify"|"reject"|"receive">("verify");
            const [reason, setReason] = useState("");
            const [fileName, setFileName] = useState("");
            const [status, setStatus] = useState<"idle"|"pending"|"done"|"error">("idle");
            const [message, setMessage] = useState("");

            const actionableDocs = (docs || []).filter(d =>
              d.status === "received" || d.status === "needs_review" || d.status === "missing"
            );

            async function handleSubmit(e: React.FormEvent) {
              e.preventDefault();
              if (!selected) return;
              setStatus("pending");
              setMessage("");
              try {
                const body: any = { action };
                if (action === "receive") body.fileName = fileName;
                if (action === "reject") body.reason = reason;
                const result = await tools.host_setDocumentStatus({
                  id: clientId,
                  docId: selected,
                  body
                });
                if (result?.status === "pending-approval") {
                  setStatus("pending");
                  setMessage("Action submitted — awaiting approval.");
                } else {
                  setStatus("done");
                  setMessage("Document status updated.");
                }
              } catch (err: any) {
                setStatus("error");
                setMessage("Something went wrong. Please try again.");
              }
            }

            const selectedDoc = actionableDocs.find(d => d.id === selected);

            return (
              <Surface>
                <Stack gap={3}>
                  <Text variant="heading" text="Update document status"/>
                  <form onSubmit={handleSubmit}>
                    <Stack gap={3}>
                      <Select
                        label="Document"
                        options={actionableDocs}
                        labelField="name"
                        valueField="id"
                        value={selected}
                        placeholder="Choose a document…"
                        onChange={(v: string) => { setSelected(v); setStatus("idle"); setMessage(""); }}
                      />
                      {selected && (
                        <Select
                          label="Action"
                          options={[
                            { label: "Verify (mark correct)", value: "verify" },
                            { label: "Reject (return to missing)", value: "reject" },
                            { label: "Receive (mark uploaded)", value: "receive" }
                          ]}
                          labelField="label"
                          valueField="value"
                          value={action}
                          onChange={(v: any) => { setAction(v); setStatus("idle"); setMessage(""); }}
                        />
                      )}
                      {selected && action === "receive" && (
                        <Input
                          label="File name"
                          value={fileName}
                          placeholder="e.g. W2_2025.pdf"
                          onChange={(v: string) => setFileName(v)}
                        />
                      )}
                      {selected && action === "reject" && (
                        <Textarea
                          label="Rejection reason (shown to client)"
                          value={reason}
                          placeholder="Explain what's wrong or missing…"
                          rows={3}
                          onChange={(v: string) => setReason(v)}
                        />
                      )}
                      {selected && (
                        <Button
                          label={status === "pending" ? "Awaiting approval…" : "Update status"}
                          variant="primary"
                          disabled={status === "pending"}
                        />
                      )}
                      {message && (
                        <Callout tone={status === "error" ? "danger" : status === "done" ? "success" : "info"} title={message}/>
                      )}
                    </Stack>
                  </form>
                </Stack>
              </Surface>
            );
          }

components.MessageThread:
export default function MessageThread({ clientId, messages }: { clientId: string; messages: any[] }) {
            const [body, setBody] = useState("");
            const [author, setAuthor] = useState("Firm");
            const [status, setStatus] = useState<"idle"|"pending"|"done"|"error">("idle");
            const [statusMsg, setStatusMsg] = useState("");

            async function handleSend(e: React.FormEvent) {
              e.preventDefault();
              if (!body.trim()) return;
              setStatus("pending");
              setStatusMsg("");
              try {
                const result = await tools.host_sendClientMessage({
                  id: clientId,
                  body: { body: body.trim(), author }
                });
                if (result?.status === "pending-approval") {
                  setStatus("pending");
                  setStatusMsg("Message submitted — awaiting approval.");
                } else {
                  setStatus("done");
                  setStatusMsg("Message sent.");
                  setBody("");
                }
              } catch {
                setStatus("error");
                setStatusMsg("Failed to send. Please try again.");
              }
            }

            const thread = (messages || []);

            return (
              <Surface>
                <Stack gap={4}>
                  <Stack gap={2}>
                    {thread.length === 0 && (
                      <Text variant="caption" text="No messages yet — send the first one below."/>
                    )}
                    {thread.map((msg: any, i: number) => {
                      const isClient = msg.author?.toLowerCase() === "client" || msg.direction === "inbound";
                      return (
                        <div
                          key={msg.id || i}
                          style={{
                            display: "flex",
                            flexDirection: "column",
                            alignItems: isClient ? "flex-start" : "flex-end",
                            gap: 2
                          }}
                        >
                          <div
                            style={{
                              background: isClient ? "var(--vendo-color-background)" : "var(--vendo-color-accent)",
                              color: isClient ? "var(--vendo-color-text)" : "var(--vendo-color-accent-text)",
                              borderRadius: "var(--vendo-radius-medium)",
                              padding: "10px 14px",
                              maxWidth: "80%",
                              fontSize: "var(--vendo-font-size)",
                              fontFamily: "var(--vendo-font-family)",
                              border: isClient ? "1px solid var(--vendo-color-border)" : "none"
                            }}
                          >
                            {msg.body || msg.text || msg.content || "(no content)"}
                          </div>
                          <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
                            <span style={{ fontSize: "12px", color: "var(--vendo-color-muted)", fontFamily: "var(--vendo-font-family)" }}>
                              {msg.author || (isClient ? "Client" : "Firm")}
                            </span>
                            {msg.sentAt || msg.createdAt ? (
                              <span style={{ fontSize: "12px", color: "var(--vendo-color-muted)", fontFamily: "var(--vendo-font-family)" }}>
                                {fmt.dateTime(msg.sentAt || msg.createdAt)}
                              </span>
                            ) : null}
                          </div>
                        </div>
                      );
                    })}
                  </Stack>
                  <Divider/>
                  <form onSubmit={handleSend}>
                    <Stack gap={2}>
                      <Textarea
                        label="New message"
                        value={body}
                        placeholder="Write a message to the client…"
                        rows={3}
                        onChange={(v: string) => setBody(v)}
                      />
                      <Input
                        label="From (staff name)"
                        value={author}
                        placeholder="Your name"
                        onChange={(v: string) => setAuthor(v)}
                      />
                      <Button
                        label={status === "pending" ? "Awaiting approval…" : "Send message"}
                        variant="primary"
                        disabled={status === "pending" || !body.trim()}
                      />
                      {statusMsg && (
                        <Callout
                          tone={status === "error" ? "danger" : status === "done" ? "success" : "info"}
                          title={statusMsg}
                        />
                      )}
                    </Stack>
                  </form>
                </Stack>
              </Surface>
            );
          }
